        if (record.started_at) {
          const duration = Date.now() - new Date(record.started_at).getTime();
          const hours = Math.floor(duration / 3600000);
          const minutes = Math.floor((duration % 3600000) / 60000);
          return `${hours}h ${minutes}m (进行中)`;
