              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '48px', color: '#1890ff', marginBottom: '16px' }}>
                  {optimizationStats?.formula_generation_methods.initial_design || 0}
                </div>
                <div style={{ fontSize: '16px', color: '#666' }}>
